   103→<body>
   104→  <div class="calculator">
   105→    <div class="display" id="display">0</div>
   106→    <div class="buttons">
   107→      <button class="number" onclick="appendNumber('7')">7</button>
   108→      <button class="number" onclick="appendNumber('8')">8</button>
   109→      <button class="number" onclick="appendNumber('9')">9</button>
   110→      <button class="operator" onclick="appendOperator('+')">+</button>
   111→
   112→      <button class="number" onclick="appendNumber('4')">4</button>
   113→      <button class="number" onclick="appendNumber('5')">5</button>
   114→      <button class="number" onclick="appendNumber('6')">6</button>
   115→      <button class="operator" onclick="appendOperator('-')">−</button>
   116→
   117→      <button class="number" onclick="appendNumber('1')">1</button>
   118→      <button class="number" onclick="appendNumber('2')">2</button>
   119→      <button class="number" onclick="appendNumber('3')">3</button>
   120→      <button class="operator" onclick="appendOperator('*')">×</button>
   121→
   122→      <button class="number" onclick="appendNumber('0')" style="grid-column: span 2;">0</button>
   123→      <button class="number" onclick="appendNumber('.')">.</button>
   124→      <button class="operator" onclick="appendOperator('/')">÷</button>
   125→
   126→      <button class="clear" onclick="clearDisplay()">C</button>
   127→      <button class="equals" onclick="calculate()">=</button>
   128→    </div>
   129→  </div>
   130→
   131→  <script>
   132→    let display = document.getElementById('display');
   133→    let currentValue = '0';
   134→    let previousValue = '';
   135→    let operation = null;
   136→    let shouldResetDisplay = false;
   137→
   138→    function updateDisplay() {
   139→      display.textContent = currentValue;
   140→    }
   141→
   142→    function appendNumber(num) {
   143→      if (shouldResetDisplay) {
   144→        currentValue = num;
   145→        shouldResetDisplay = false;
   146→      } else {
   147→        if (currentValue === '0' && num !== '.') {
   148→          currentValue = num;
   149→        } else if (num === '.' && currentValue.includes('.')) {
   150→          return;
   151→        } else {
   152→          currentValue += num;
   153→        }
   154→      }
   155→      updateDisplay();
   156→    }
   157→
   158→    function appendOperator(op) {
   159→      if (operation !== null) {
   160→        calculate();
   161→      }
   162→      previousValue = currentValue;
   163→      operation = op;
   164→      shouldResetDisplay = true;
   165→    }
   166→
   167→    function calculate() {
   168→      if (operation === null || shouldResetDisplay) return;
   169→
   170→      const prev = parseFloat(previousValue);
   171→      const current = parseFloat(currentValue);
   172→      let result;
   173→
   174→      switch (operation) {
   175→        case '+':
   176→          result = prev + current;
   177→          break;
   178→        case '-':
   179→          result = prev - current;
   180→          break;
   181→        case '*':
   182→          result = prev * current;
   183→          break;
   184→        case '/':
   185→          result = current !== 0 ? prev / current : 0;
   186→          break;
   187→        default:
   188→          return;
   189→      }
   190→
   191→      currentValue = String(result);
   192→      operation = null;
   193→      shouldResetDisplay = true;
   194→      updateDisplay();
   195→    }
   196→
   197→    function clearDisplay() {
   198→      currentValue = '0';
   199→      previousValue = '';
   200→      operation = null;
   201→      shouldResetDisplay = false;
   202→      updateDisplay();
   203→    }
   204→
   205→    updateDisplay();
   206→  </script>
