  const num = parseFloat(currentValue);
  let result;

  switch (func) {
    case 'log':
      // 상용 로그 (밑이 10)
      result = Math.log10(num);
      break;
    case 'ln':
      // 자연 로그 (밑이 e)
      result = Math.log(num);
      break;
    case 'sqrt':
      // 제곱근
      result = Math.sqrt(num);
      break;
    case 'pow':
      // 제곱
      result = num * num;
      break;
    case 'percent':
      // 백분율
      result = num / 100;
      break;
    case 'invert':
      // 역수 (1/x)
      result = num !== 0 ? 1 / num : 0;
      break;
    default:
      return;
  }

  currentValue = String(result);
  operation = null;
  shouldResetDisplay = true;
  updateDisplay();
}

updateDisplay();

